  def _format_object(predicate: str, obj: str) -> str:
          """Add appropriate units to numeric objects based on predicate."""
          # Try to interpret the object as a number
          try:
              num = float(obj)
              is_num = True
          except (ValueError, TypeError):
              is_num = False

          if is_num:
              # Determine unit based on predicate keywords
              if "Feet" in predicate:
                  # Use integer feet when possible
                  return f"{int(num)} feet"
              if "Metre" in predicate or "Metres" in predicate:
                  return f"{int(num)} metres"
              if "elevationAboveTheSeaLevel" in predicate:
                  # Default to metres for elevation unless feet are explicit
                  return f"{num} metres"
          return obj

      for t in triples:
          verb = verb_map.get(t.predicate, "has")
          obj_formatted = _format_object(t.predicate, t.object)
          phrase = f"{verb} {obj_formatted}"
          groups.setdefault(t.subject, []).append(phrase)
